/**

 * * CodeParse – STT workflow

*/// ---------- Extract transcription ----------
const transcription =
  $items("extractTranscription")[0]?.json?.transcription || "";

// ---------- Patient FHIR ----------
const patientRow = $items("verifyPatient")[0]?.json || {};
const patient = patientRow.resource || {};

// ---------- Practitioner FHIR ----------
const practitionerRow = $items("verifyPractitioner")[0]?.json || {};
const practitioner = practitionerRow.resource || {};

// ---------- Patient extraction ----------
const patientName =
  patient.name?.[0]
    ? `${(patient.name[0].given || []).join(" ")} ${patient.name[0].family || ""}`.trim()
    : "NA";

const patientDob = patient.birthDate || "NA";
const patientGender = patient.gender || "NA";

const patientMrn =
  patient.identifier?.find(i => i.system?.toLowerCase().includes("mrn"))?.value || "NA";

// ---------- Practitioner extraction ----------
const practitionerName =
  practitioner.name?.[0]
    ? `${(practitioner.name[0].prefix || []).join(" ")} ${(practitioner.name[0].given || []).join(" ")} ${practitioner.name[0].family || ""}`.trim()
    : "NA";

const practitionerEmail =
  practitioner.telecom?.find(t => t.system === "email")?.value || "NA";

// ---------- Encounter date ----------
const encounterDate = new Date().toISOString().split("T")[0];

// ---------- Final normalized payload ----------
return [
  {
    json: {
      clinical_text_input: transcription,
      encounter_date: encounterDate,

      patient_details: {
        name: patientName,
        dob: patientDob,
        gender: patientGender,
        mrn: patientMrn
      },

      provider_details: {
        name: practitionerName,
        email: practitionerEmail
      }
    }
  }
];

